+import { cacheLife, cacheTag } from 'next/cache';
+
+const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
+
+const seedProducts = [
+  { sku: 'LAP-001', name: 'Performance Laptop', basePrice: 1299, inventory: 42 },
+  { sku: 'PHN-002', name: 'Field Phone', basePrice: 799, inventory: 118 },
+  { sku: 'TAB-003', name: 'Retail Tablet', basePrice: 649, inventory: 37 },
+  { sku: 'HDP-004', name: 'Studio Headphones', basePrice: 249, inventory: 73 },
+  { sku: 'WTC-005', name: 'Warehouse Watch', basePrice: 329, inventory: 21 }
+];
+
+let catalogRevision = 1;
+let lastCompletedSyncAt = new Date('2026-07-10T08:00:00.000Z');
+let inFlightSync = null;
+
+function buildCatalogSnapshot() {
+  return seedProducts.map((product, index) => {
+    const inventoryShift = ((catalogRevision + index) % 5) - 2;
+    const nextInventory = Math.max(0, product.inventory + inventoryShift * 3);
+    const priceDelta = catalogRevision % 2 === 0 ? 15 : -10;
+
+    return {
+      sku: product.sku,
+      name: product.name,
+      price: product.basePrice + priceDelta,
+      inventory: nextInventory,
+      availability: nextInventory > 0 ? 'In stock' : 'Backorder'
+    };
+  });
+}
+
+export async function getProductCatalog() {
+  'use cache';
+
+  cacheLife('hours');
+  cacheTag('products');
+
+  // Simulate a slower upstream-backed catalog read that should be reused.
+  await delay(120);
+
+  return {
+    revision: catalogRevision,
+    syncedAt: lastCompletedSyncAt.toISOString(),
+    products: buildCatalogSnapshot()
+  };
+}
+
+export function getCatalogSyncStatus() {
+  return {
+    isSyncing: inFlightSync !== null,
+    lastCompletedSyncAt: lastCompletedSyncAt.toISOString()
+  };
+}
+
+export function triggerCatalogSync() {
+  if (inFlightSync) {
+    return inFlightSync;
+  }
+
+  inFlightSync = (async () => {
+    // Simulate a large ERP/PIM import that should not block the admin request.
+    await delay(1800);
+    catalogRevision += 1;
+    lastCompletedSyncAt = new Date();
+  })().finally(() => {
+    inFlightSync = null;
+  });
+
+  return inFlightSync;
+}
